from dataclasses import dataclass, field
from decimal import Decimal
from datetime import datetime
from typing import Optional


@dataclass
class Transaction:
    """Represents a single payment transaction in the Ledgerly system."""
    transaction_id: str
    merchant_id: str
    amount: Decimal
    currency: str = "USD"
    timestamp: datetime = field(default_factory=datetime.utcnow)
    status: str = "completed"  # completed, pending, failed, refunded
    description: Optional[str] = None

    def __post_init__(self):
        if not isinstance(self.amount, Decimal):
            self.amount = Decimal(str(self.amount))


@dataclass
class TransactionBatch:
    """A batch of transactions for a given date and merchant."""
    merchant_id: str
    date: str  # YYYY-MM-DD format
    transactions: list = field(default_factory=list)

    @property
    def total(self) -> Decimal:
        return sum((t.amount for t in self.transactions if t.status == "completed"), Decimal("0.00"))

    @property
    def count(self) -> int:
        return len([t for t in self.transactions if t.status == "completed"])

from dataclasses import dataclass, field
from decimal import Decimal
from typing import Optional


@dataclass
class Merchant:
    """Represents a merchant account in the Ledgerly system."""
    merchant_id: str
    name: str
    settlement_account: str
    fee_rate: Decimal = Decimal("0.029")  # 2.9% default processing fee
    active: bool = True

    def __post_init__(self):
        if not isinstance(self.fee_rate, Decimal):
            self.fee_rate = Decimal(str(self.fee_rate))


@dataclass
class MerchantReport:
    """Merchant-reported daily totals, submitted via API."""
    merchant_id: str
    date: str  # YYYY-MM-DD format
    reported_total: Decimal
    reported_count: int
    submitted_at: Optional[str] = None

    def __post_init__(self):
        if not isinstance(self.reported_total, Decimal):
            self.reported_total = Decimal(str(self.reported_total))

from datetime import datetime, timedelta
from config import REPORT_DATE_FORMAT


def today_str() -> str:
    """Return today's date as a YYYY-MM-DD string."""
    return datetime.utcnow().strftime(REPORT_DATE_FORMAT)


def yesterday_str() -> str:
    """Return yesterday's date as a YYYY-MM-DD string."""
    return (datetime.utcnow() - timedelta(days=1)).strftime(REPORT_DATE_FORMAT)


def parse_date(date_str: str) -> datetime:
    """Parse a YYYY-MM-DD string into a datetime object."""
    return datetime.strptime(date_str, REPORT_DATE_FORMAT)
